import React, { type FunctionComponent, useState, useRef } from "react";
import { Tree } from "primereact/tree";
import { Flex } from "../../_compat"; // Adjust import
import type {ITreeViewProps, TreeProps} from "@lmb-it/kitsconcerto-types";
import { useTreeViewController } from "./useTreeViewController";
import TreeViewToolbar from "./Toolbar";
import { useKitsTheme } from "../../contexts/Theme";
import "./treeview.scss";

const TreeView = <T=any,>(props:ITreeViewProps<T>) => {
    const {
        treeValue,
        selectedNode,
        filterValue,
        build,
        setFilterValue,
        expandAll,
        collapseAll,
        operations,
        treeProps
    } = useTreeViewController(props);

    const {
        nodeTemplate,
        containerProps,
        hideSearchBox,
        hideDisabledButton,
        expendableControls,
        hideToolbar: propsHideToolbar // If passed from parent
    } = props;

    const { resolveToken } = useKitsTheme();
    const primaryColor = resolveToken('primary');
    const primaryTextColor = resolveToken('bg') || '#fff';

    // Ref for the PrimeReact Tree instance (for filtering)
    const treeRef = useRef<TreeProps>(null);

    const shouldHideToolbar =
        propsHideToolbar ||
        (!!hideSearchBox && !!hideDisabledButton && !expendableControls);

    return (
        <Flex id={"tree-view"} w={"full"} h={"full"} flexDirection={"column"} {...containerProps}>
            {!shouldHideToolbar && (
                <TreeViewToolbar
                    props={props}
                    filterValue={filterValue}
                    setFilterValue={setFilterValue}
                    //@ts-ignore
                    treeRef={treeRef.current}
                    selectedNode={selectedNode}
                    expandAll={expandAll}
                    collapseAll={collapseAll}
                    onAddNode={operations.onAddNode}
                    onAddNodeItem={operations.onAddNodeItem}
                    onDeleteNode={operations.onDeleteNode}
                    onEditNode={operations.onEditNode}
                    build={build}
                />
            )}

            <Tree
                //@ts-ignore
                ref={treeRef}
                className={`${!shouldHideToolbar ? "border-none" : ""} h-auto overflow-auto`}
                // Spread props from Hook
                {...treeProps}
                // Passthrough props
                filter={!shouldHideToolbar}
                filterMode={"lenient"}
                filterTemplate={<></>}
                nodeTemplate={(node, options) => {
                    const isSelected = node.key == selectedNode?.key;
                    return (
                        <Flex
                            w={"full"}
                            justifyContent={"flex-start"}
                            alignItems={"center"}
                        >
                            {/*@ts-ignore*/}
                            {!!nodeTemplate && nodeTemplate(node, options)}

                            {!nodeTemplate && (
                                <span className={options.className}>{node.label}</span>
                            )}

                            {isSelected && (
                                <style>
                                    {`
                    #tree-view .p-treenode-content.${node.className} {
                        background-color: ${primaryColor} !important;
                        color: ${primaryTextColor} !important;
                    }
                  `}
                                </style>
                            )}
                        </Flex>
                    );
                }}
                pt={{
                    content: {
                        style: {
                            transition: 'background-color 0.2s',
                        },
                        className: "hover:surface-200",
                    },
                    toggler: {
                        style: {
                            color: "inherit",
                        },
                    },
                    nodeIcon: {
                        style: {
                            color: "inherit",
                        },
                    },
                }}
            />
        </Flex>
    );
};

export default TreeView;
